#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <cstddef>

const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    // Create an intrusive_storage object with the vector's size as block_size
    hexi::detail::intrusive_storage<const std::vector<uint8_t>::size_type, uint8_t> storage(buffer.size());

    // Use read_offset() to calculate the read pointer
    return storage.storage.data() + storage.read_offset();
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    // Create an intrusive_storage object with the vector's size as block_size
    hexi::detail::intrusive_storage<std::vector<uint8_t>::size_type, uint8_t> storage(buffer.size());

    // Use write_offset() to calculate the write pointer
    return storage.storage.data() + storage.write_offset();
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    // Create an intrusive_storage object with the vector's size as block_size
    hexi::detail::intrusive_storage<const std::vector<uint8_t>::size_type, uint8_t> storage(buffer.size());

    // Calculate readable size using write_offset() - read_offset()
    auto readable_size = storage.write_offset() - storage.read_offset();

    // Calculate free space as block_size - write_offset()
    auto free_space = buffer.size() - storage.write_offset();

    return {readable_size, free_space};
}
```

**Explanation:**

1. **get_read_pointer**: Creates an `intrusive_storage` object using the vector's size as the template parameter for `block_size`. Uses the `read_offset()` function to calculate the read pointer by adding the offset to the storage data pointer.

2. **get_write_pointer**: Similar to `get_read_pointer`, but creates a non-const version and uses `write_offset()` to get the write pointer.

3. **check_buffer_space**: Calculates both readable size (difference between write and read offsets) and free space (total buffer size minus write offset), returning both in the `BufferInfo` structure.

The solution correctly uses the Hexi library's functions as specified in the assessment objectives, leveraging the `intrusive_storage` template with the vector's size as the block size parameter.

