    // Create a file_buffer object using the provided file path
    hexi::file_buffer buffer(file_path);

    // Check if the file buffer is in a valid state (no errors occurred during construction)
    if (!buffer) {
        return {}; // Return empty vector if file couldn't be opened or other error occurred
    }

    // Create a destination buffer (vector) with the required header size
    std::vector<uint8_t> header_data(header_size);

    // Use the copy method to copy header data without advancing the read pointer
    // The copy method handles the file seeking and reading internally
    buffer.copy(header_data.data(), header_size);

    // Return the vector containing the copied header data
    return header_data;
}
```

