template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(const hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_preview) {
    // Check if the requested bytes exceed the available data
    if (bytes_to_preview > buffer.size()) {
        throw std::runtime_error("Preview request exceeds available data");
    }

    // Create a vector to hold the preview data
    std::vector<uint8_t> preview_vector(bytes_to_preview);

    // Use the copy method to copy data without advancing the read pointer
    buffer.copy(preview_vector.data(), bytes_to_preview);

    return preview_vector;
}
